import{_ as a,c as o,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"라이선스: BSL 조항 설명 | Plannotator","description":"Plannotator의 Business Source License 1.1 (BSL) 라이선스 조항과 상업적 사용 제한에 대해 알아봅니다. 허용되는 사용 시나리오, 향후 변경 계획 및 2030년 Apache 2.0 전환 일정을 확인하세요.","frontmatter":{"title":"라이선스: BSL 조항 설명 | Plannotator","sidebarTitle":"상업적 사용 규칙 이해하기","subtitle":"라이선스: BSL 조항 설명","description":"Plannotator의 Business Source License 1.1 (BSL) 라이선스 조항과 상업적 사용 제한에 대해 알아봅니다. 허용되는 사용 시나리오, 향후 변경 계획 및 2030년 Apache 2.0 전환 일정을 확인하세요.","tags":["라이선스","BSL-1.1","상업적 사용"],"prerequisite":[],"order":3},"headers":[],"relativePath":"ko/backnotprop/plannotator/appendix/license/index.md","filePath":"ko/backnotprop/plannotator/appendix/license/index.md"}'),n={name:"ko/backnotprop/plannotator/appendix/license/index.md"};function e(i,t,s,d,h,p){return l(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="plannotator-라이선스-안내" tabindex="-1">Plannotator 라이선스 안내 <a class="header-anchor" href="#plannotator-라이선스-안내" aria-label="Permalink to &quot;Plannotator 라이선스 안내&quot;">​</a></h1><h2 id="학습-목표" tabindex="-1">학습 목표 <a class="header-anchor" href="#학습-목표" aria-label="Permalink to &quot;학습 목표&quot;">​</a></h2><ul><li>Plannotator가 사용하는 라이선스 유형과 핵심 조항 이해하기</li><li>허용되는 사용 시나리오와 제한되는 시나리오 명확히 구분하기</li><li>라이선스의 향후 변경 일정 파악하기</li><li>상업용 라이선스 취득 방법 및 권한 부여자 연락처 알아보기</li></ul><h2 id="알아야-할-사항" tabindex="-1">알아야 할 사항 <a class="header-anchor" href="#알아야-할-사항" aria-label="Permalink to &quot;알아야 할 사항&quot;">​</a></h2><p>Plannotator는 **Business Source License 1.1 (BSL)**을 오픈소스 라이선스로 채택하고 있습니다. 이는 상업적 가치를 보호하면서도 궁극적으로 프로젝트를 완전히 오픈소스화하기 위해 설계된 특수한 라이선스입니다.</p><h2 id="핵심-조항" tabindex="-1">핵심 조항 <a class="header-anchor" href="#핵심-조항" aria-label="Permalink to &quot;핵심 조항&quot;">​</a></h2><h3 id="라이선스-유형" tabindex="-1">라이선스 유형 <a class="header-anchor" href="#라이선스-유형" aria-label="Permalink to &quot;라이선스 유형&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td><strong>라이선스 명칭</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>저작권자</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>라이선스 대상 프로젝트</strong></td><td>plannotator</td></tr><tr><td><strong>변경 일자</strong></td><td>2030-01-01</td></tr><tr><td><strong>변경 후 라이선스</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">BSL이란?</p><p>Business Source License는 MariaDB에서 개발한 특수 라이선스입니다. 단기적으로는 특정 상업적 용도를 제한하지만, 특정 날짜 이후에는 소프트웨어를 완전한 오픈소스 라이선스(예: Apache 2.0)로 전환할 것을 약속합니다. 이 모델을 통해 오픈소스 프로젝트는 상업화 과정에서 지속 가능한 수익을 얻으면서도 장기적으로 커뮤니티에 개방될 수 있습니다.</p></div><h3 id="허용되는-사용-방식" tabindex="-1">허용되는 사용 방식 <a class="header-anchor" href="#허용되는-사용-방식" aria-label="Permalink to &quot;허용되는 사용 방식&quot;">​</a></h3><p>BSL 1.1 조항에 따라 다음이 가능합니다:</p><ul><li><p>✅ <strong>복제, 수정 및 파생 저작물 생성</strong></p><ul><li>Plannotator를 기반으로 2차 개발 가능</li><li>필요에 맞게 소스 코드 수정 가능</li></ul></li><li><p>✅ <strong>재배포</strong></p><ul><li>원본 또는 수정된 버전 배포 가능</li><li>원본 라이선스 고지 유지 필수</li></ul></li><li><p>✅ <strong>비프로덕션 환경 사용</strong></p><ul><li>내부 개발, 테스트 및 평가</li><li>개인 학습 및 연구</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">개인 및 기업 내부의 광범위한 사용</p><p>BSL의 &quot;비프로덕션 환경 사용&quot; 정의는 매우 광범위하며, 개인 및 회사 내부의 다양한 시나리오를 포함합니다. 귀하와 팀원(독립 계약자 포함)은 Plannotator를 개발, 테스트 및 배포에 자유롭게 사용할 수 있습니다.</p></div><h3 id="사용-제한-중요" tabindex="-1">사용 제한 (중요!) <a class="header-anchor" href="#사용-제한-중요" aria-label="Permalink to &quot;사용 제한 (중요!)&quot;">​</a></h3><p><strong>핵심 제한</strong>: Plannotator를 **계획, 컨텍스트 또는 승인 서비스(Planning, Context, or Approval Service)**에 사용할 수 없습니다.</p><h4 id="계획-컨텍스트-또는-승인-서비스-란" tabindex="-1">&quot;계획, 컨텍스트 또는 승인 서비스&quot;란? <a class="header-anchor" href="#계획-컨텍스트-또는-승인-서비스-란" aria-label="Permalink to &quot;&quot;계획, 컨텍스트 또는 승인 서비스&quot;란?&quot;">​</a></h4><p><strong>제3자</strong>(직원 및 독립 계약자 제외)가 직접 또는 간접적인 조작을 통해 Plannotator 기능에 접근할 수 있도록 하는 모든 상업 제품이 제한 대상 서비스에 해당합니다. 구체적으로 다음을 포함하되 이에 국한되지 않습니다:</p><ul><li><p><strong>클라우드 서비스 제공업체</strong></p><ul><li>SaaS 플랫폼이 서비스의 일부로 Plannotator 기능 제공</li><li>호스팅 서비스 제공업체가 고객 또는 구독자에게 Plannotator 제공</li></ul></li><li><p><strong>인프라 서비스</strong></p><ul><li>데이터센터 서비스 제공업체</li><li>클라우드 컴퓨팅 플랫폼 제공업체</li></ul></li><li><p><strong>유사 서비스의 제3자</strong></p><ul><li>위 기관 및 그 계열사가 제공하는 모든 서비스 포함</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">상업적 사용 경고</p><p>Plannotator를 상업 서비스의 일부로 제3자에게 제공할 계획이라면, 반드시 사전에 상업용 라이선스를 취득해야 합니다. 이 조항을 위반하면 현재 및 모든 버전의 Plannotator에 대한 사용 권한이 자동으로 종료됩니다.</p></div><h2 id="라이선스-변경-일정" tabindex="-1">라이선스 변경 일정 <a class="header-anchor" href="#라이선스-변경-일정" aria-label="Permalink to &quot;라이선스 변경 일정&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시점</th><th>라이선스 유형</th><th>설명</th></tr></thead><tbody><tr><td><strong>현재 - 2030-01-01</strong></td><td>BSL 1.1</td><td>제한된 오픈소스 라이선스</td></tr><tr><td><strong>2030-01-01 이후</strong></td><td>Apache 2.0</td><td>완전한 오픈소스, 상업적 제한 없음</td></tr></tbody></table><h3 id="변경-후-어떻게-되나요" tabindex="-1">변경 후 어떻게 되나요? <a class="header-anchor" href="#변경-후-어떻게-되나요" aria-label="Permalink to &quot;변경 후 어떻게 되나요?&quot;">​</a></h3><p>2030년 1월 1일부터 Plannotator는 자동으로 <strong>Apache License 2.0</strong>으로 전환됩니다. 이는 다음을 의미합니다:</p><ul><li>✅ 모든 상업적 제한 해제</li><li>✅ 모든 상업적 목적에 자유롭게 사용 가능</li><li>✅ 모든 SaaS 서비스에 통합 가능</li><li>✅ 관대한 오픈소스 라이선스 기준 충족</li></ul><h2 id="상업용-라이선스" tabindex="-1">상업용 라이선스 <a class="header-anchor" href="#상업용-라이선스" aria-label="Permalink to &quot;상업용 라이선스&quot;">​</a></h2><p>BSL 제한을 준수하지 않고 Plannotator를 사용해야 하는 경우(예: 계획, 컨텍스트 또는 승인 서비스용), 다음을 수행할 수 있습니다:</p><ol><li><p><strong>상업용 라이선스 구매</strong></p><ul><li>backnotprop 또는 공인 리셀러로부터 구매</li><li>BSL 제한 없이 사용 권한 획득</li></ul></li><li><p><strong>권한 부여자에게 연락</strong></p><ul><li>이메일: backnotprop</li><li>사용 시나리오 및 요구 사항 설명</li></ul></li></ol><h2 id="자주-묻는-질문" tabindex="-1">자주 묻는 질문 <a class="header-anchor" href="#자주-묻는-질문" aria-label="Permalink to &quot;자주 묻는 질문&quot;">​</a></h2><h3 id="회사-내부에서-plannotator를-사용할-수-있나요" tabindex="-1">회사 내부에서 Plannotator를 사용할 수 있나요? <a class="header-anchor" href="#회사-내부에서-plannotator를-사용할-수-있나요" aria-label="Permalink to &quot;회사 내부에서 Plannotator를 사용할 수 있나요?&quot;">​</a></h3><p><strong>예.</strong> BSL은 귀하와 직원, 독립 계약자가 내부 개발, 테스트 및 배포에 Plannotator를 사용하는 것을 명시적으로 허용합니다. 제한은 <strong>제3자</strong>(직원 및 계약자가 아닌)에게 서비스를 제공하는 시나리오에만 적용됩니다.</p><h3 id="plannotator를-기반으로-자체-제품을-개발할-수-있나요" tabindex="-1">Plannotator를 기반으로 자체 제품을 개발할 수 있나요? <a class="header-anchor" href="#plannotator를-기반으로-자체-제품을-개발할-수-있나요" aria-label="Permalink to &quot;Plannotator를 기반으로 자체 제품을 개발할 수 있나요?&quot;">​</a></h3><p><strong>예, 조건부로 가능합니다.</strong> 제품이 다음에 해당하는 경우:</p><ul><li>내부 도구: ✅ 허용</li><li>개인 프로젝트: ✅ 허용</li><li>오픈소스 프로젝트: ✅ 허용 (BSL 라이선스 유지)</li><li>상업 제품: ❓ &quot;계획, 컨텍스트 또는 승인 서비스&quot;에 해당하는지 평가 필요</li></ul><h3 id="저희-회사는-saas-제공업체인데-사용할-수-있나요" tabindex="-1">저희 회사는 SaaS 제공업체인데, 사용할 수 있나요? <a class="header-anchor" href="#저희-회사는-saas-제공업체인데-사용할-수-있나요" aria-label="Permalink to &quot;저희 회사는 SaaS 제공업체인데, 사용할 수 있나요?&quot;">​</a></h3><p><strong>상업용 라이선스가 필요합니다.</strong> SaaS 제품이 Plannotator 기능을 고객에게 제공하는 경우(기능의 일부로 제공하더라도), 이는 제한된 상업 서비스에 해당하므로 반드시 상업용 라이선스를 구매해야 합니다.</p><h3 id="_2030년-이후에는-plannotator를-어떤-용도로든-사용할-수-있나요" tabindex="-1">2030년 이후에는 Plannotator를 어떤 용도로든 사용할 수 있나요? <a class="header-anchor" href="#_2030년-이후에는-plannotator를-어떤-용도로든-사용할-수-있나요" aria-label="Permalink to &quot;2030년 이후에는 Plannotator를 어떤 용도로든 사용할 수 있나요?&quot;">​</a></h3><p><strong>예.</strong> 변경 일자부터 Plannotator는 Apache 2.0 라이선스를 채택하며, 모든 상업적 제한이 해제되어 어떤 용도로든 자유롭게 사용할 수 있습니다.</p><h2 id="라이선스-전문" tabindex="-1">라이선스 전문 <a class="header-anchor" href="#라이선스-전문" aria-label="Permalink to &quot;라이선스 전문&quot;">​</a></h2><p>Business Source License 1.1 전문은 프로젝트 루트 디렉토리의 <code>LICENSE</code> 파일을 참조하세요.</p><h2 id="연락처" tabindex="-1">연락처 <a class="header-anchor" href="#연락처" aria-label="Permalink to &quot;연락처&quot;">​</a></h2><p>상업용 라이선스가 필요하거나 기타 문의 사항이 있으시면 연락해 주세요:</p><ul><li><strong>권한 부여자</strong>: backnotprop</li><li><strong>프로젝트 저장소</strong>: <a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../../changelog/release-notes/">변경 로그</a>**를 확인합니다.</p><p>다음 내용을 확인할 수 있습니다:</p><ul><li>Plannotator의 버전 히스토리</li><li>각 버전의 새로운 기능 및 개선 사항</li><li>주요 버그 수정</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인 번호</th></tr></thead><tbody><tr><td>라이선스 고지</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>라이선스 전문</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>핵심 정보</strong>:</p><ul><li>라이선스 유형: Business Source License 1.1 (BSL)</li><li>저작권자: backnotprop (c) 2025</li><li>변경 일자: 2030-01-01</li><li>변경 후 라이선스: Apache License, Version 2.0</li><li>주요 제한: 계획, 컨텍스트 또는 승인 서비스에 사용 불가</li></ul></details>',47)])])}const b=a(n,[["render",e]]);export{u as __pageData,b as default};
